import{_ as t,o as a,c as n,ag as s}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"Design Spec: Input Bar","description":"","frontmatter":{},"headers":[],"relativePath":"design-spec/03_input_bar.md","filePath":"design-spec/03_input_bar.md","lastUpdated":1775368115000}'),i={name:"design-spec/03_input_bar.md"};function r(o,e,d,l,c,p){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="design-spec-input-bar" tabindex="-1">Design Spec: Input Bar <a class="header-anchor" href="#design-spec-input-bar" aria-label="Permalink to &quot;Design Spec: Input Bar&quot;">​</a></h1><p><strong>TS source</strong>: <code>components/PromptInput.tsx</code>, <code>hooks/useTextInput.ts</code>, <code>hooks/fileSuggestions.ts</code></p><hr><h2 id="visual-layout" tabindex="-1">Visual Layout <a class="header-anchor" href="#visual-layout" aria-label="Permalink to &quot;Visual Layout&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                                               [fast ⚡]</span></span>
<span class="line"><span>╰──────────────────────────────────────────────────────╯</span></span>
<span class="line"><span>  &gt; _</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><strong>Border</strong>: bottom only, rounded corners (<code>╰──╯</code> style)</li><li><strong>Top-right label</strong>: optional mode indicator (fast mode <code>⚡</code>, plan mode <code>📋</code>, bash mode <code>!</code>)</li><li><strong>Prompt symbol</strong>: <code>&gt;</code> followed by space, then cursor</li><li><strong>Background</strong>: transparent (inherits terminal)</li><li><strong>Top margin</strong>: 1 blank line above the border</li></ul><h3 id="multi-line-state" tabindex="-1">Multi-line state <a class="header-anchor" href="#multi-line-state" aria-label="Permalink to &quot;Multi-line state&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╰──────────────────────────────────────────────────────╯</span></span>
<span class="line"><span>  &gt; First line of input</span></span>
<span class="line"><span>    Second line (Shift+Enter was pressed)</span></span>
<span class="line"><span>    Third line_</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Lines beyond the first have <strong>2 spaces</strong> indent (aligns with text after <code>&gt; </code>).</p><hr><h2 id="border-color-states" tabindex="-1">Border Color States <a class="header-anchor" href="#border-color-states" aria-label="Permalink to &quot;Border Color States&quot;">​</a></h2><table tabindex="0"><thead><tr><th>State</th><th>Border color</th></tr></thead><tbody><tr><td>Default (idle)</td><td><code>theme.inactive</code> (gray)</td></tr><tr><td>Focused / typing</td><td><code>theme.permission</code> (blue)</td></tr><tr><td>Bash mode (<code>!</code> prefix)</td><td><code>theme.bash_border</code> (hot pink <code>rgb(255,0,135)</code>)</td></tr><tr><td>Plan mode active</td><td><code>theme.plan_mode</code> (teal)</td></tr><tr><td>Agent thinking</td><td><code>theme.spinner</code> (blue, shimmer pulse)</td></tr></tbody></table><h3 id="shimmer-during-agent-thinking" tabindex="-1">Shimmer during agent thinking <a class="header-anchor" href="#shimmer-during-agent-thinking" aria-label="Permalink to &quot;Shimmer during agent thinking&quot;">​</a></h3><p>When the agent is processing, the border pulses between <code>theme.spinner</code> and <code>theme.spinner_shimmer</code> at 500ms intervals.</p><hr><h2 id="placeholder-text" tabindex="-1">Placeholder Text <a class="header-anchor" href="#placeholder-text" aria-label="Permalink to &quot;Placeholder Text&quot;">​</a></h2><p>Shown only when input is completely empty:</p><table tabindex="0"><thead><tr><th>Context</th><th>Placeholder</th></tr></thead><tbody><tr><td>Default</td><td><code>Ask anything...</code> (dimmed, <code>theme.inactive</code>)</td></tr><tr><td>After compact</td><td><code>Context compacted. Continue...</code></td></tr><tr><td>In plan mode</td><td><code>Describe your plan...</code></td></tr><tr><td>Agent waiting</td><td><code>(agent is thinking...)</code> — not user-editable</td></tr></tbody></table><hr><h2 id="mode-prefixes" tabindex="-1">Mode Prefixes <a class="header-anchor" href="#mode-prefixes" aria-label="Permalink to &quot;Mode Prefixes&quot;">​</a></h2><p>Certain characters at the start of input trigger special modes:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Mode</th><th>Border color</th></tr></thead><tbody><tr><td><code>!</code></td><td>Bash shortcut — runs as shell command directly</td><td>Hot pink</td></tr><tr><td><code>/</code></td><td>Slash command — dispatched to command system</td><td>Blue (default)</td></tr><tr><td><code>@</code></td><td>File/mention — triggers file path autocomplete</td><td>Blue (default)</td></tr></tbody></table><hr><h2 id="typeahead-autocomplete-dropdown" tabindex="-1">Typeahead / Autocomplete Dropdown <a class="header-anchor" href="#typeahead-autocomplete-dropdown" aria-label="Permalink to &quot;Typeahead / Autocomplete Dropdown&quot;">​</a></h2><p>Appears <strong>below</strong> the input bar when suggestions are available.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╰──────────────────────────────────────────────────────╯</span></span>
<span class="line"><span>  &gt; src/main@</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ▶ src/main.rs           [rust]   Ctrl+→ to accept</span></span>
<span class="line"><span>    src/main_test.rs      [rust]</span></span>
<span class="line"><span>    src/main_helpers.rs   [rust]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="dropdown-layout" tabindex="-1">Dropdown layout <a class="header-anchor" href="#dropdown-layout" aria-label="Permalink to &quot;Dropdown layout&quot;">​</a></h3><ul><li><strong>Position</strong>: Immediately below the input border, full width</li><li><strong>Max height</strong>: <code>floor(terminal_rows / 2)</code> — never takes more than half the screen</li><li><strong>Scroll</strong>: If more items than fit, scrolls (no scrollbar, just clips)</li></ul><h3 id="item-format" tabindex="-1">Item format <a class="header-anchor" href="#item-format" aria-label="Permalink to &quot;Item format&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  [indicator] filename.ext    [tag/lang]   shortcut hint</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><strong>Left indent</strong>: 2 spaces</li><li><strong>Focused item</strong>: inverted colors (white bg, dark text)</li><li><strong>Unfocused</strong>: normal text</li><li><strong>Tag</strong>: dimmed, right-aligned</li><li><strong>Shortcut hint</strong>: <code>theme.inactive</code>, far right</li></ul><h3 id="suggestion-types-and-their-indicators" tabindex="-1">Suggestion types and their indicators <a class="header-anchor" href="#suggestion-types-and-their-indicators" aria-label="Permalink to &quot;Suggestion types and their indicators&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Indicator</th><th>Color</th></tr></thead><tbody><tr><td>File path</td><td><code></code> (space)</td><td>default</td></tr><tr><td>Directory</td><td><code>/</code> suffix</td><td>default</td></tr><tr><td>Slash command</td><td><code>/</code> prefix</td><td><code>theme.suggestion</code> blue</td></tr><tr><td>Sub-agent @mention</td><td><code>@</code> prefix</td><td>agent&#39;s team color</td></tr><tr><td>Recent input</td><td><code>↑</code></td><td><code>theme.inactive</code></td></tr></tbody></table><h3 id="keyboard-navigation" tabindex="-1">Keyboard navigation <a class="header-anchor" href="#keyboard-navigation" aria-label="Permalink to &quot;Keyboard navigation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>↓</code></td><td>Move focus down</td></tr><tr><td><code>↑</code></td><td>Move focus up</td></tr><tr><td><code>Tab</code></td><td>Accept focused suggestion</td></tr><tr><td><code>Ctrl+→</code></td><td>Accept word from focused suggestion</td></tr><tr><td><code>Esc</code></td><td>Dismiss dropdown</td></tr><tr><td><code>Enter</code></td><td>Accept focused suggestion AND submit</td></tr></tbody></table><hr><h2 id="file-mention-syntax" tabindex="-1">@file Mention Syntax <a class="header-anchor" href="#file-mention-syntax" aria-label="Permalink to &quot;@file Mention Syntax&quot;">​</a></h2><p>When user types <code>@</code> followed by a path fragment, file suggestions appear.</p><h3 id="display-in-input-text" tabindex="-1">Display in input text <a class="header-anchor" href="#display-in-input-text" aria-label="Permalink to &quot;Display in input text&quot;">​</a></h3><p>Accepted file paths appear as inline colored text (not a separate widget):</p><ul><li>Color: <code>theme.suggestion</code> (blue)</li><li>No background, no border — just colored text in the input stream</li></ul><h3 id="with-line-range" tabindex="-1">With line range <a class="header-anchor" href="#with-line-range" aria-label="Permalink to &quot;With line range&quot;">​</a></h3><p><code>@src/main.rs:10-25</code> — includes only lines 10–25 of the file in context.</p><p>When submitted, the agent receives the file content inline in the user message:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[File: src/main.rs lines 10-25]</span></span>
<span class="line"><span>\`\`\`rust</span></span>
<span class="line"><span>fn main() {</span></span>
<span class="line"><span>    ...</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="image-paste-attachment-chips" tabindex="-1">Image Paste (Attachment Chips) <a class="header-anchor" href="#image-paste-attachment-chips" aria-label="Permalink to &quot;Image Paste (Attachment Chips)&quot;">​</a></h2><p>When user pastes an image from clipboard, a text chip is inserted at the cursor:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  &gt; Fix this error [Image #1] in the auth module</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="chip-appearance" tabindex="-1">Chip appearance <a class="header-anchor" href="#chip-appearance" aria-label="Permalink to &quot;Chip appearance&quot;">​</a></h3><ul><li><strong>Format</strong>: <code>[Image #N]</code> where N auto-increments from 1</li><li><strong>Normal state</strong>: standard input text color</li><li><strong>Cursor-on-chip state</strong>: inverted colors (chip selected for deletion)</li><li><strong>Deletion</strong>: Backspace at chip start deletes entire chip</li></ul><h3 id="text-paste-chips" tabindex="-1">Text paste chips <a class="header-anchor" href="#text-paste-chips" aria-label="Permalink to &quot;Text paste chips&quot;">​</a></h3><p>Large text pastes (&gt; ~5000 chars) become a reference chip:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  &gt; Here is the log output [Pasted text #1 +234 lines] what went wrong?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>Format: <code>[Pasted text #N +M lines]</code> — M = number of newlines</li><li>Zero-line paste: <code>[Pasted text #N]</code></li><li>Truncated paste: <code>[...Truncated text #N +M lines...]</code></li></ul><hr><h2 id="input-history-navigation" tabindex="-1">Input History Navigation <a class="header-anchor" href="#input-history-navigation" aria-label="Permalink to &quot;Input History Navigation&quot;">​</a></h2><blockquote><p><strong>Status: ✅ Implemented in v0.5.0</strong> (<code>crates/piko-tui/src/history.rs</code>, <code>crates/piko-tui/src/app.rs</code>)</p></blockquote><p>When input is <strong>empty</strong>:</p><ul><li><code>↑</code> — replace input with previous submitted message</li><li><code>↓</code> — navigate forward in history (toward current empty)</li></ul><p>Visual: input text replaces, cursor goes to end.</p><p><strong>Implementation notes:</strong></p><ul><li><code>InputHistory</code> struct tracks <code>entries: Vec&lt;String&gt;</code> and <code>idx: Option&lt;usize&gt;</code>.</li><li>Whitespace-only submissions are silently ignored.</li><li><code>↑</code> when input has content but navigation is active continues navigating (allows full round-trips).</li><li>Typing while browsing exits navigation mode, keeping the recalled text editable.</li><li><code>↑</code>/<code>↓</code> fall back to chat-pane scroll when history is empty or not navigating.</li></ul><hr><h2 id="character-line-limits" tabindex="-1">Character/Line Limits <a class="header-anchor" href="#character-line-limits" aria-label="Permalink to &quot;Character/Line Limits&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Limit</th><th>Value</th><th>Behavior</th></tr></thead><tbody><tr><td>Max visible input lines</td><td>~10</td><td>Input scrolls vertically</td></tr><tr><td>Max paste inline</td><td>~1024 chars</td><td>Larger becomes reference chip</td></tr><tr><td>Max paste total</td><td>~5000 chars</td><td>Beyond this, truncated chip shown</td></tr><tr><td>Max input submit</td><td>No hard limit</td><td>Very large inputs may hit API limits</td></tr></tbody></table>`,66)])])}const m=t(i,[["render",r]]);export{u as __pageData,m as default};
